type Spec = {
  id: string
  title: string
  description: string
  cuisine: string
  category: string
  difficulty: 'Easy' | 'Medium' | 'Hard'
  minutes: [number, number]
  servings: number
  taste?: number
  tags: string[]
  collections?: string[]
  ingredients: [string, number, string][]
  steps: string[]
}

function buildRecipe(spec: Spec): Recipe {
  return {
    id: spec.id,
    title: spec.title,
    description: spec.description,
    cuisine: spec.cuisine,
    category: spec.category,
    collections: spec.collections,
    difficulty: spec.difficulty,
    prepMinutes: spec.minutes[0],
    cookMinutes: spec.minutes[1],
    servings: spec.servings,
    taste: spec.taste,
    tags: spec.tags,
    ingredients: spec.ingredients.map(([name, amount, unit]) => ({ name, amount, unit })),
    steps: spec.steps,
  }
}

